from prometheus_client import Collector, GaugeMetricFamily, start_http_server
from flask import Flask, request, jsonify
import requests

app = Flask(__name__)
metrics = {}

def register_counter(path, user_id, session_id):
    if (path, user_id) not in metrics:
        metrics[(path, user_id)] = Collector(
            GaugeMetricFamily('requests_count', 'Total requests per unique user-path combination', values=[('__name__', 0)])
        )
    metrics[(path, user_id)][f'{user_id}:{session_id}'].inc()

def init():
    for rule in PrometheusEndpoint.rules:
        app.add_url_rule(rule[0], rule[1], PrometheusEndpoint.wrapper(rule[2]))

class PrometheusEndpoint:
    rules = [
        ('/metrics', '/metrics', PrometheusMetrics),
        (r'/\w+/\d+\/(.*)', r'/{user_id}/{session_id}/\1', PrometheusRequest)
    ]

    @staticmethod
    def wrapper(view_func):
        def wrapper(*args, **kwargs):
            register_counter(request.path, request.args.get('user_id'), request.args.get('session_id'))
            return view_func(*args, **kwargs)
        return wrapper

class PrometheusMetrics:
    @app.route('/metrics')
    def metrics():
        result = []
        for (path, user_id), metric in metrics.items():
            result.append(metric.collect())
        return "\n".join(str(m) for m in result)

class PrometheusRequest:
    @app.route(r'/{user_id}/{session_id}/<path>')
    def request(user_id, session_id, path):
        try:
            response = requests.get(f'http://example.com/{path}')
            return jsonify({'status': response.status_code})
        except Exception as e:
            return str(e)

if __name__ == "__main__":
    init()
    start_http_server(8000)